const items = $input.all();

return items.map(({ json }) => {
  const raw = json.resultJson ?? json.data?.resultJson ?? json.param?.resultJson;
  let url = null;

  try {
    const obj = typeof raw === 'string' ? JSON.parse(raw) : raw;
    if (Array.isArray(obj?.resultUrls) && obj.resultUrls.length) {
      url = obj.resultUrls[0];
    } else if (obj?.resultUrl) {
      url = obj.resultUrl;
    } else if (obj?.url) {
      url = obj.url;
    }
  } catch {
    const m = String(raw ?? '').match(/https?:\/\/[^\s"']+/);
    url = m ? m[0] : null;
  }

  // Sade çıktı: sadece URL
  return { json: { url } };
});

// Mode: Run Once for All Items
// Language: JavaScript

const items = $input.all();

let urls = [];

// Toparla1, aggregateAllItemData ile tek item içinde
// data: [ {...}, {...}, ... ] şeklinde veri gönderiyor.
for (const item of items) {
  const dataArray = item.json?.data;
  if (!Array.isArray(dataArray)) continue;

  for (const row of dataArray) {
    // Güvenli şekilde resultUrls'e kadar in
    const resultUrls = row?.data?.response?.resultUrls;

    if (Array.isArray(resultUrls)) {
      for (const u of resultUrls) {
        if (typeof u === 'string' && /^https?:\/\//.test(u)) {
          urls.push(u);
        }
      }
    }
  }
}

// Aynı URL’leri temizle, sırayı koru
const uniqueUrls = [...new Set(urls)];

// Replicate node’undaki body ile uyumlu field’lar
return [
  {
    json: {
      // Düz array hali
      video_files: uniqueUrls,

      // Senin Replicate body'inde kullanılan string hali:
      // "url1","url2","url3"
      video_files_inner: uniqueUrls.map(u => `"${u}"`).join(','),

      // Kaç video var diye ekstra bilgi
      video_count: uniqueUrls.length,
    },
  },
];
